import{c as t,S as h,j as a,m as i}from"./chunks/framework.8aa1YH_s.js";const u=JSON.parse('{"title":"Dashboard - Trang tổng quan (Admin)","description":"","frontmatter":{},"headers":[],"relativePath":"admin/dashboard.md","filePath":"admin/dashboard.md","lastUpdated":0}'),o={name:"admin/dashboard.md"};function g(r,n,d,c,s,l){return h(),a("div",null,[...n[0]||(n[0]=[i('<h1 id="dashboard-trang-tong-quan-admin" tabindex="-1">Dashboard - Trang tổng quan (Admin) <a class="header-anchor" href="#dashboard-trang-tong-quan-admin" aria-label="Permalink to “Dashboard - Trang tổng quan (Admin)”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/dashboard</code></p><p>Đây là trang đầu tiên hiển thị sau khi bạn đăng nhập tài khoản quản trị. Mục tiêu là cho bạn một cái nhìn nhanh về sức khỏe của hệ thống.</p><h2 id="cac-the-so-lieu-cards" tabindex="-1">Các thẻ số liệu (Cards) <a class="header-anchor" href="#cac-the-so-lieu-cards" aria-label="Permalink to “Các thẻ số liệu (Cards)”">​</a></h2><p>Phần trên cùng hiển thị các con số tổng:</p><table tabindex="0"><thead><tr><th>Thẻ</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td><strong>Tổng số học viên</strong></td><td>Số tài khoản học viên đang có trong hệ thống</td></tr><tr><td><strong>Tổng số giáo viên</strong></td><td>Số giáo viên đang hoạt động</td></tr><tr><td><strong>Tổng số khóa học</strong></td><td>Số khóa học đã công khai + đang chuẩn bị</td></tr><tr><td><strong>Tổng số đề thi</strong></td><td>Số đề thi đã tạo (gồm cả đề ôn, đề mẫu, bộ đề)</td></tr><tr><td><strong>Hóa đơn tháng này</strong></td><td>Số hóa đơn đã thanh toán thành công trong tháng</td></tr><tr><td><strong>Doanh thu tháng này</strong></td><td>Tổng tiền đã thu (đã trừ khuyến mãi)</td></tr></tbody></table><p>Bấm vào từng thẻ để nhảy đến trang chi tiết tương ứng.</p><h2 id="bieu-đo" tabindex="-1">Biểu đồ <a class="header-anchor" href="#bieu-đo" aria-label="Permalink to “Biểu đồ”">​</a></h2><ul><li><strong>Biểu đồ doanh thu theo ngày / tháng</strong> - giúp theo dõi xu hướng kinh doanh.</li><li><strong>Biểu đồ học viên mới đăng ký</strong> - theo dõi mức tăng trưởng người dùng.</li><li><strong>Top khóa học bán chạy</strong> - các khóa có lượng đăng ký lớn nhất trong khoảng thời gian chọn.</li><li><strong>Tỷ lệ học viên hoạt động</strong> - học viên có hoạt động (học bài / làm bài / mua) trong 7-30 ngày qua.</li></ul><blockquote><p>💡 Bạn có thể đổi khoảng thời gian (7 ngày / 30 ngày / quý / năm) bằng bộ chọn ở góc trên bên phải biểu đồ.</p></blockquote><h2 id="hoat-đong-gan-đay" tabindex="-1">Hoạt động gần đây <a class="header-anchor" href="#hoat-đong-gan-đay" aria-label="Permalink to “Hoạt động gần đây”">​</a></h2><ul><li>Danh sách <strong>học viên mới đăng ký</strong> trong 24 giờ qua.</li><li>Danh sách <strong>hóa đơn mới</strong> cần xử lý.</li><li>Danh sách <strong>câu hỏi mới</strong> chưa trả lời (Hỏi đáp).</li></ul><p>Bấm tên học viên / hóa đơn để mở chi tiết.</p><h2 id="goi-y-dung-dashboard-hang-ngay" tabindex="-1">Gợi ý dùng Dashboard hằng ngày <a class="header-anchor" href="#goi-y-dung-dashboard-hang-ngay" aria-label="Permalink to “Gợi ý dùng Dashboard hằng ngày”">​</a></h2><ol><li>Mở Dashboard mỗi sáng để check: <ul><li>Có hóa đơn nào pending quá 24h chưa?</li><li>Có học viên mới đăng ký cần được chăm sóc không?</li><li>Doanh thu hôm qua so với cùng kỳ tuần trước?</li></ul></li><li>Cuối tuần kiểm tra biểu đồ xu hướng để báo cáo.</li><li>Khi có sự cố (lượng học viên đăng ký bất thường, doanh thu đột biến) → vào <a href="./thong-ke">Thống kê</a> để phân tích sâu.</li></ol><h2 id="khi-so-lieu-khong-khop-voi-thuc-te" tabindex="-1">Khi số liệu không khớp với thực tế <a class="header-anchor" href="#khi-so-lieu-khong-khop-voi-thuc-te" aria-label="Permalink to “Khi số liệu không khớp với thực tế”">​</a></h2><ul><li>Bấm nút <strong>Làm mới</strong> (refresh icon) ở góc phải để load lại dữ liệu mới nhất.</li><li>Số liệu doanh thu được tính từ các hóa đơn <strong>đã thanh toán</strong>, không tính hóa đơn đang chờ.</li><li>Nếu vẫn sai, vào <a href="./thong-ke">Thống kê</a> để xem báo cáo chi tiết hoặc liên hệ IT để kiểm tra.</li></ul>',17)])])}const b=t(o,[["render",g]]);export{u as __pageData,b as default};
